#include <bits/stdc++.h>
using namespace std;
int n,d,a[502][502],b[502][502];
int main(){
	scanf("%d%d",&n,&d);
	for(int i=1;i<=n;i++)
		for(int j=1;j<=n;j++)
			scanf("%d",&a[i][j]);
	int sum=0;
	for(int i=1;i<=n;i++)
		for(int j=1;j<=n;j++){
			b[i][j]=(a[i][j]<0?-1:1);
			a[i][j]=abs(a[i][j]);
			if((i+j)&1)
				sum+=min(a[i][j]%(2*d),2*d-a[i][j]%(2*d));
			else
				sum+=abs(a[i][j]%(2*d)-d);
		}
	for(int i=1;i<=n;i++){
		for(int j=1;j<=n;j++){
			if((i+j)&(sum*2<=d*n*n)){
				if(a[i][j]%(2*d)<2*d-a[i][j]%(2*d))
					printf("%d ",b[i][j]*(a[i][j]/(2*d)*2*d));
				else
					printf("%d ",b[i][j]*((a[i][j]/(2*d)+1)*2*d));
			}else{
				printf("%d ",b[i][j]*(a[i][j]/(2*d)*2*d+d));
			}
		}
		if(i<n)
		    printf("\n");
	}
	return 0;
}
